1013:     /**
1014:      * Remove expired offsets for the given group.
1015:      *
1016:      * @param groupId The group id.
1017:      * @param records The list of records to populate with offset commit tombstone records.
1018:      *
1019:      * @return True if no offsets exist after expiry and no pending transactional offsets exist,
1020:      *         false otherwise.
1021:      */
1022:     public boolean cleanupExpiredOffsets(String groupId, List<CoordinatorRecord> records) {
1023:         TimelineHashMap<String, TimelineHashMap<Integer, OffsetAndMetadata>> offsetsByTopic =
1024:             offsets.offsetsByGroup.get(groupId);
1025:         if (offsetsByTopic == null) {
1026:             return !openTransactions.contains(groupId);
1027:         }
1028: 
1029:         // We expect the group to exist.
1030:         Group group = groupMetadataManager.group(groupId);
1031:         long currentTimestampMs = time.milliseconds();
1032:         Optional<OffsetExpirationCondition> offsetExpirationCondition = group.offsetExpirationCondition();
1033: 
1034:         if (offsetExpirationCondition.isEmpty()) {
1035:             return false;
1036:         }
1037: 
1038:         AtomicBoolean allOffsetsExpired = new AtomicBoolean(true);
1039:         OffsetExpirationCondition condition = offsetExpirationCondition.get();
1040: 
1041:         offsetsByTopic.forEach((topic, partitions) -> {
1042:             if (!group.isSubscribedToTopic(topic)) {
1043:                 partitions.forEach((partition, offsetAndMetadata) -> {
1044:                     // We don't expire the offset yet if there is a pending transactional offset for the partition.
1045:                     if (condition.isOffsetExpired(offsetAndMetadata, currentTimestampMs, config.offsetsRetentionMs()) &&
1046:                         !hasPendingTransactionalOffsets(groupId, topic, partition)) {
1047:                         appendOffsetCommitTombstone(groupId, topic, partition, records);
1048:                         log.debug("[GroupId {}] Expired offset for partition={}-{}", groupId, topic, partition);
1049:                     } else {
1050:                         allOffsetsExpired.set(false);
1051:                     }
1052:                 });
1053:             } else {
1054:                 allOffsetsExpired.set(false);
1055:             }
1056:         });
1057:         metrics.record(OFFSET_EXPIRED_SENSOR_NAME, records.size());
1058: 
1059:         // We don't want to remove the group if there are ongoing transactions with undeleted offsets.
1060:         return allOffsetsExpired.get() && !openTransactions.contains(groupId);
1061:     }
