1063:     /**
1064:      * Remove offsets of the partitions that have been deleted.
1065:      *
1066:      * @param topicPartitions   The partitions that have been deleted.
1067:      * @return The list of tombstones (offset commit) to append.
1068:      */
1069:     public List<CoordinatorRecord> onPartitionsDeleted(
1070:         List<TopicPartition> topicPartitions
1071:     ) {
1072:         List<CoordinatorRecord> records = new ArrayList<>();
1073: 
1074:         Map<String, List<Integer>> partitionsByTopic = new HashMap<>();
1075:         topicPartitions.forEach(tp -> partitionsByTopic
1076:             .computeIfAbsent(tp.topic(), __ -> new ArrayList<>())
1077:             .add(tp.partition())
1078:         );
1079: 
1080:         Consumer<Offsets> delete = offsetsToClean -> {
1081:             offsetsToClean.offsetsByGroup.forEach((groupId, topicOffsets) -> {
1082:                 topicOffsets.forEach((topic, partitionOffsets) -> {
1083:                     if (partitionsByTopic.containsKey(topic)) {
1084:                         partitionsByTopic.get(topic).forEach(partition -> {
1085:                             if (partitionOffsets.containsKey(partition)) {
1086:                                 appendOffsetCommitTombstone(groupId, topic, partition, records);
1087:                             }
1088:                         });
1089:                     }
1090:                 });
1091:             });
1092:         };
1093: 
1094:         // Delete the partitions from the main storage.
1095:         delete.accept(offsets);
1096:         // Delete the partitions from the pending transactional offsets.
1097:         pendingTransactionalOffsets.forEach((__, offsets) -> delete.accept(offsets));
1098: 
1099:         return records;
1100:     }
